<?php
/**
 * Model generator template
 * @var string $modelName
 * @var string $tableName
 * @var array $columns
 * @var array $references
 * @var string $nameSpace
 * @var array $columns
 * @var array $references
 * @var array $referrers
 */
    echo "<?php\n";
?>
