/**
 * Generated by UApp create command
 * Date: <?=date('Y-m-d H:i:s')?>
 */

namespace app\models;
use educalliance\umvc\Model;

/**
 * Class <?= $modelName ?>
 *
<?php foreach ($columns as $name => $column) {
    $ref = $references[$name] ?? null;
    $reference = $ref ? " references {$ref['foreign_table']}" : '';
    $len = $column['len'];;
    $key = match(strtoupper($column['key'])) { 'PRI' => ' PRIMARY KEY', 'UNI' => ' UNIQUE', default => '' };
    $def = strtoupper($column['type']) . ($len  > -1 ? "($len)" : '') . $key . ($column['not null'] ? ' NOT NULL' : '') . ($column['has default'] ? " DEFAULT '{$column['default']}' " : '');
    echo " * @property-read {$column['php-type']} \${$column['php-name']} -- $def$reference\n";
} ?>
 */
class <?= $modelName ?> extends Model
{
    /**
     * Must return the name of the table.
     * Defined explicitly, the default rule is not working on derived classes :-(
     *
     * @return string
     */
    public static function tableName(): string
    {
        return '<?= $tableName ?>';
    }

	public static function primaryKey(): array
    {
		return [<?= implode(',', array_filter(array_map(fn($column) => $column['key'] == 'PRI' ? "'" . $column['php-name'] . "'" : null, $columns))) ?>];
    }

    public static function attributeLabels(): array
    {
		return [
<?php foreach ($columns as $name => $column) {
                echo "            '" . $column['php-name'] . "' => '" . $column['label'] . "',\n";
            } ?>
        ];
    }
}

